def latest_tool_result(turns, key):
    value = None
    for turn in turns:
        if turn.get('role') == 'tool_result' and turn.get('key') == key:
            value = turn.get('value')
    return value

def agent_used_value(turns, key):
    used = None
    for turn in turns:
        if turn.get('role') == 'agent':
            carried = turn.get('carried', {})
            if key in carried:
                used = carried[key]
    return used

def carried_forward(turns, key):
    expected = latest_tool_result(turns, key)
    actual = agent_used_value(turns, key)
    return expected is not None and actual == expected

def carried_forward(turns, key):
    expected = None
    for turn in turns:
        if turn.get('role') == 'tool_result' and turn.get('key') == key:
            expected = turn.get('value')
    actual = None
    for turn in turns:
        if turn.get('role') == 'agent' and key in turn.get('carried', {}):
            actual = turn.get('carried', {})[key]
    return expected is not None and actual == expected
